// ============================================
// BUILD EVENING STANDUP SUMMARY
// ============================================

const standups = $('Fetch Evening Standups').all();
const activeMembers = $('Fetch Active Members').all();

const now = $now.setZone('Asia/Kolkata');
const today = now.toFormat('EEEE, MMMM d, yyyy');
const currentTime = now.toFormat('h:mm a');

console.log('=== EVENING SUMMARY ===');
console.log('Date:', today);
console.log('Time:', currentTime);
console.log('Active Members:', activeMembers.length);
console.log('Standups Received:', standups.length);

// Calculate statistics
const totalActive = activeMembers.length;
const totalResponded = standups.length;
const responseRate = totalActive > 0 ? ((totalResponded / totalActive) * 100).toFixed(1) : 0;

// Find missing members
const respondedIds = new Set(standups.map(s => {
  const devId = s.json.property_developer_id || s.json.Developer_ID || '';
  return devId;
}));

const missingMembers = activeMembers
  .filter(m => {
    const devId = m.json.property_developer_id || m.json.Developer_ID || '';
    return !respondedIds.has(devId);
  })
  .map(m => m.json.property_full_name || m.json.Full_Name || 'Unknown');

console.log('Missing Members:', missingMembers);

// Build message header
let message = `🌙 *Evening Standup Summary*\n`;
message += `📅 ${today}\n`;
message += `━━━━━━━━━━━━━━━━━━\n\n`;

// Response statistics
message += `📈 *Response Statistics*\n`;
message += `✅ Responded: ${totalResponded}/${totalActive} (${responseRate}%)\n`;
if (missingMembers.length > 0) {
  message += `❌ Missing: ${missingMembers.length}\n`;
}
message += `\n`;

// Missing responses
if (missingMembers.length > 0) {
  message += `⚠️ *Missing Responses:*\n`;
  missingMembers.forEach(name => {
    message += `   • ${name}\n`;
  });
  message += `\n`;
}

// Help needed section
const needHelp = standups.filter(s => {
  const help = s.json.property_help_needed || s.json.Help_Needed || '';
  const noHelpPatterns = ['no', 'none', 'n/a', 'na', 'no help needed', 'not needed', 'nope'];
  const helpLower = help.toLowerCase().trim();
  return help.trim().length > 0 && 
         !noHelpPatterns.some(pattern => helpLower === pattern || helpLower.includes(pattern));
});

console.log('Help Needed Count:', needHelp.length);

if (needHelp.length > 0) {
  message += `🆘 *Help Requested (${needHelp.length}):*\n`;
  needHelp.forEach(s => {
    const devId = s.json.property_developer_id || s.json.Developer_ID;
    const member = activeMembers.find(m => {
      const memberDevId = m.json.property_developer_id || m.json.Developer_ID;
      return memberDevId === devId;
    });
    const name = member ? (member.json.property_full_name || member.json.Full_Name) : devId;
    const help = s.json.property_help_needed || s.json.Help_Needed || '';
    const helpText = help.substring(0, 100);
    message += `\n👤 *${name}*\n`;
    message += `   ${helpText}${help.length > 100 ? '...' : ''}\n`;
  });
  message += `\n`;
} else {
  message += `✅ *No Help Requested*\n\n`;
}

// Task completion status
const completed = standups.filter(s => {
  const completion = (s.json.property_task_completion_info || s.json.Task_Completion_Info || '').toLowerCase();
  return completion.includes('yes') || completion.includes('complete') || completion.includes('done') || completion.includes('all complete');
});

const incomplete = standups.filter(s => {
  const completion = (s.json.property_task_completion_info || s.json.Task_Completion_Info || '').toLowerCase();
  return completion.includes('no') || completion.includes('pending') || completion.includes('incomplete');
});

console.log('Completed:', completed.length);
console.log('Incomplete:', incomplete.length);

message += `━━━━━━━━━━━━━━━━━━\n`;
message += `✅ *Task Completion Status:*\n`;
message += `   ✓ Completed: ${completed.length}\n`;
message += `   ⏳ Pending: ${incomplete.length}\n`;
message += `   ℹ️ Other: ${standups.length - completed.length - incomplete.length}\n\n`;

// Today's accomplishments
message += `━━━━━━━━━━━━━━━━━━\n`;
message += `🎯 *Today's Accomplishments:*\n\n`;

const displayCount = Math.min(5, standups.length);
standups.slice(0, displayCount).forEach(s => {
  const devId = s.json.property_developer_id || s.json.Developer_ID;
  const member = activeMembers.find(m => {
    const memberDevId = m.json.property_developer_id || m.json.Developer_ID;
    return memberDevId === devId;
  });
  const name = member ? (member.json.property_full_name || member.json.Full_Name) : devId;
  const completedWork = s.json.property_today_completed || s.json.Today_Completed || '';

  if (completedWork.trim()) {
    const workText = completedWork.substring(0, 80);
    message += `👤 *${name}*\n`;
    message += `   ${workText}${completedWork.length > 80 ? '...' : ''}\n\n`;
  }
});

if (standups.length > 5) {
  message += `_...and ${standups.length - 5} more team members_\n\n`;
}

// Footer
message += `━━━━━━━━━━━━━━━━━━\n`;
message += `🕐 Generated at ${currentTime} IST`;

console.log('=== SUMMARY COMPLETE ===');

return {
  message: message,
  total_active: totalActive,
  total_responded: totalResponded,
  response_rate: parseFloat(responseRate),
  missing_count: missingMembers.length,
  help_needed_count: needHelp.length,
  completed_count: completed.length,
  incomplete_count: incomplete.length,
  missing_members: missingMembers
};

// Get all merged input items
const allItems = $input.all();

console.log('📥 Total items received:', allItems.length);

// Normalize field names function
const normalizeRecord = (record) => ({
  Developer_ID: record.property_developer_id || record.Developer_ID || '',
  Full_Name: record.property_full_name || record.Full_Name || '',
  Active_Status: record.property_active_status || record.Active_Status || '',
  Responded: record.property_responded || record.Responded || false,
  Blockers: record.property_blockers || record.Blockers || '',
  Date: record.property_date || record.Date || '',
  Completed_Yesterday: record.property_completed_yesterday || record.Completed_Yesterday || '',
  Goals_Today: record.property_goals_today || record.Goals_Today || '',
  Plans_Tickets: record.property_plans_tickets || record.Plans_Tickets || '',
  Help_Needed: record.property_help_needed || record.Help_Needed || '',
  Slack_User_ID: record.property_slack_user_id || record.Slack_User_ID || ''
});

// Process all items and separate by Developer_ID
const memberMap = new Map();
const standupMap = new Map();

allItems.forEach(item => {
  const normalized = normalizeRecord(item.json);

  // Skip if no Developer_ID
  if (!normalized.Developer_ID) return;

  // If this record has Active_Status, it's a member record
  if (normalized.Active_Status === 'Active') {
    memberMap.set(normalized.Developer_ID, normalized);
  }

  // If this record has Date and Responded=true, it's a standup response
  if (normalized.Date && normalized.Responded === true) {
    standupMap.set(normalized.Developer_ID, normalized);
  }
});

const activeMembers = Array.from(memberMap.values());
const standupResponses = Array.from(standupMap.values());

console.log('👥 Active members:', activeMembers.length);
console.log('✅ Standup responses:', standupResponses.length);

// Get current India time
const now = new Date();

const todayFormatted = new Intl.DateTimeFormat("en-IN", {
  timeZone: "Asia/Kolkata",
  weekday: "long",
  year: "numeric",
  month: "long",
  day: "numeric"
}).format(now);

const currentTime = new Intl.DateTimeFormat("en-IN", {
  timeZone: "Asia/Kolkata",
  hour: "numeric",
  minute: "2-digit",
  hour12: true
}).format(now);

// Calculate statistics
const totalActive = activeMembers.length;
const respondedIds = new Set(standupResponses.map(s => s.Developer_ID));
const totalResponded = respondedIds.size;
const totalNotAttended = Math.max(0, totalActive - totalResponded);
const responseRate = totalActive > 0 ? ((totalResponded / totalActive) * 100).toFixed(1) : "0.0";

// Separate members into attended and not attended
const respondedMembers = activeMembers.filter(m => respondedIds.has(m.Developer_ID));
const notAttendedMembers = activeMembers.filter(m => !respondedIds.has(m.Developer_ID));

console.log('✅ Responded members:', respondedMembers.length);
console.log('❌ Not attended members:', notAttendedMembers.length);

// Function to check if text indicates "no blocker"
const isNoBlocker = (text) => {
  if (!text) return true;

  const cleaned = text.toString().trim().toLowerCase();
  if (cleaned.length === 0) return true;

  const noneWords = [
    "no", "none", "n/a", "na", "nil", "nothing", "nope",
    "no blocker", "no blockers", "no blocking", "no blocks",
    "not applicable", "not available", "empty", "null"
  ];

  if (noneWords.includes(cleaned)) return true;

  const noBlockerPatterns = [
    /^no[\s\-_]*blocker/i,
    /^no[\s\-_]*block/i,
    /^none$/i,
    /^n\/?a$/i,
    /^nil$/i
  ];

  return noBlockerPatterns.some(pattern => pattern.test(cleaned));
};

// Find members with actual blockers
const membersWithBlockers = standupResponses.filter(s => {
  const blockerText = s.Blockers || s.Help_Needed || '';
  return !isNoBlocker(blockerText);
});

console.log('🚧 Members with blockers:', membersWithBlockers.length);

// Build WhatsApp formatted message
let message = `📊 *Daily Standup Summary Report*\n`;
message += `📅 Date: ${todayFormatted}\n`;
message += `🕐 Time: ${currentTime} IST\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

message += `📈 *Attendance Overview*\n`;
message += `👥 Total Active Members: ${totalActive}\n`;
message += `✅ Attended (Responded): ${totalResponded}\n`;
message += `❌ Not Attended: ${totalNotAttended}\n`;
message += `📊 Response Rate: ${responseRate}%\n\n`;

if (respondedMembers.length > 0) {
  message += `✅ *Members Who Attended (${respondedMembers.length}):*\n`;
  respondedMembers.forEach(member => {
    const name = member.Full_Name || member.Developer_ID || 'Unknown';
    message += `   • ${name}\n`;
  });
  message += `\n`;
} else {
  message += `✅ *No members have attended yet*\n\n`;
}

if (notAttendedMembers.length > 0) {
  message += `❌ *Members Who Did NOT Attend (${notAttendedMembers.length}):*\n`;
  notAttendedMembers.forEach(member => {
    const name = member.Full_Name || member.Developer_ID || 'Unknown';
    message += `   • ${name}\n`;
  });
  message += `\n`;
} else {
  message += `🎉 *All members have attended!*\n\n`;
}

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;

if (membersWithBlockers.length > 0) {
  message += `🚧 *Blockers Reported (${membersWithBlockers.length}):*\n\n`;
  membersWithBlockers.forEach(member => {
    const name = member.Full_Name || member.Developer_ID || 'Unknown';
    const blockerText = member.Blockers || member.Help_Needed || 'Not specified';
    message += `👤 *${name}*\n`;
    message += `   🚫 ${blockerText}\n\n`;
  });
} else {
  message += `✅ *No Blockers Reported*\n\n`;
}

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `📊 *Summary Statistics*\n`;
message += `• Team Size: ${totalActive}\n`;
message += `• Responses: ${totalResponded}\n`;
message += `• Pending: ${totalNotAttended}\n`;
message += `• Blockers: ${membersWithBlockers.length}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `🤖 Auto-generated Daily Standup Report\n`;
message += `⏰ Generated at ${currentTime} IST\n`;

return {
  json: {
    message,
    date: todayFormatted,
    time: currentTime,
    timestamp: now.toISOString(),
    total_active: totalActive,
    total_responded: totalResponded,
    total_not_attended: totalNotAttended,
    response_rate: parseFloat(responseRate),
    blockers_count: membersWithBlockers.length,
    responded_members: respondedMembers.map(m => ({
      id: m.Developer_ID,
      name: m.Full_Name,
      slack_user_id: m.Slack_User_ID
    })),
    not_attended_members: notAttendedMembers.map(m => ({
      id: m.Developer_ID,
      name: m.Full_Name,
      slack_user_id: m.Slack_User_ID
    })),
    blockers: membersWithBlockers.map(m => ({
      id: m.Developer_ID,
      name: m.Full_Name,
      blocker: m.Blockers || m.Help_Needed,
      completed_yesterday: m.Completed_Yesterday,
      goals_today: m.Goals_Today,
      plans_tickets: m.Plans_Tickets
    })),
    debug: {
      total_items: allItems.length,
      active_members_found: activeMembers.length,
      standup_responses_found: standupResponses.length,
      responded_ids: Array.from(respondedIds)
    }
  }
};

/**
 * Team Member JSON Validation & Normalization
 */

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json || {};

  const notionPageId = data.id || '';
  const fullName = (data.property_full_name || data.name || '').trim();
  const slackUserId = (data.property_slack_user_id || '').trim();
  const developerId = (data.property_developer_id || '').trim();
  const teamRole = (data.property_team_role || '').trim();
  const activeStatus = (data.property_active_status || '').trim();
  const communicationTool = (data.property_client_communication || '').trim();

  const errors = [];

  if (!notionPageId) errors.push('Missing Notion Page ID');
  if (!fullName) errors.push('Missing Full Name');
  if (!slackUserId) errors.push('Missing Slack User ID');
  if (!developerId) errors.push('Missing Developer ID');
  if (!teamRole) errors.push('Missing Team Role');
  if (!activeStatus) errors.push('Missing Active Status');

  const isValid = errors.length === 0;

  results.push({
    json: {
      notion_page_id: notionPageId,
      full_name: fullName,
      slack_user_id: slackUserId,
      developer_id: developerId,
      team_role: teamRole,
      active_status: activeStatus,
      client_communication: communicationTool || null,
      leave_management: Boolean(data.property_leave_management),
      leave_type: data.property_leave_type || null,
      leave_start_date: data.property_leave_start_date || null,
      leave_end_date: data.property_leave_end_date || null,
      daily_standups: Boolean(data.property_daily_standups),
      blockers_tracking: Boolean(data.property_blockers_tracking),
      is_valid: isValid,
      validation_errors: errors.length ? errors : null,
      source: 'notion',
      validated_at: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const redisValue = item.json.value;
  let sessionExists = false;
  let sessionData = null;

  if (redisValue && redisValue !== 'null' && redisValue !== '') {
    try {
      sessionData = JSON.parse(redisValue);
      sessionExists = true;
    } catch (e) {
      sessionExists = false;
    }
  }

  results.push({
    json: {
      ...item.json,
      session_exists: sessionExists,
      session_data: sessionData,
      needs_new_session: !sessionExists
    }
  });
}

return results;

/**
 * Prepare Redis session data with readiness flag
 */

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json || {};

  const slackUserId =
    data.property_user_id ||
    data.name ||
    '';

  const answers = [
    data.property_answer_1 || '',
    data.property_answer_2 || '',
    data.property_answer_3 || '',
    data.property_answer_4 || ''
  ].filter(ans => ans !== '');

  const isSessionReady = Boolean(slackUserId && data.id);

  const sessionData = {
    notion_page_id: data.id,
    slack_user_id: slackUserId,
    current_question: data.property_current_question ?? 0,
    answers,
    started_at: data.property_date?.start || new Date().toISOString(),
    last_updated: new Date().toISOString(),
    is_session_ready: isSessionReady
  };

  const redisKey = isSessionReady
    ? `morning:standup:session:${slackUserId}`
    : null;

  const redisValue = isSessionReady
    ? JSON.stringify(sessionData)
    : null;

  results.push({
    json: {
      session_data: sessionData,
      redis_key: redisKey,
      redis_value: redisValue,
      redis_ttl: 86400,
      can_write_redis: isSessionReady
    }
  });
}

return results;

const now = new Date();

return {
  status: 'NO_DEVELOPERS',
  message: 'No active developers found for daily standup',
  timestamp: now.toISOString(),
  date: now.toISOString().split('T')[0]
};

/**
 * Team Member JSON Validation & Normalization
 */

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json || {};

  const notionPageId = data.id || '';
  const fullName = (data.property_full_name || data.name || '').trim();
  const slackUserId = (data.property_slack_user_id || '').trim();
  const developerId = (data.property_developer_id || '').trim();
  const teamRole = (data.property_team_role || '').trim();
  const activeStatus = (data.property_active_status || '').trim();
  const communicationTool = (data.property_client_communication || '').trim();

  const errors = [];

  if (!notionPageId) errors.push('Missing Notion Page ID');
  if (!fullName) errors.push('Missing Full Name');
  if (!slackUserId) errors.push('Missing Slack User ID');
  if (!developerId) errors.push('Missing Developer ID');
  if (!teamRole) errors.push('Missing Team Role');
  if (!activeStatus) errors.push('Missing Active Status');

  const isValid = errors.length === 0;

  results.push({
    json: {
      notion_page_id: notionPageId,
      full_name: fullName,
      slack_user_id: slackUserId,
      developer_id: developerId,
      team_role: teamRole,
      active_status: activeStatus,
      client_communication: communicationTool || null,
      leave_management: Boolean(data.property_leave_management),
      leave_type: data.property_leave_type || null,
      leave_start_date: data.property_leave_start_date || null,
      leave_end_date: data.property_leave_end_date || null,
      daily_standups: Boolean(data.property_daily_standups),
      blockers_tracking: Boolean(data.property_blockers_tracking),
      is_valid: isValid,
      validation_errors: errors.length ? errors : null,
      source: 'notion',
      validated_at: new Date().toISOString()
    }
  });
}

return results;

const devData = $('Check if valid member (evening)').first().json;
const redisInputs = $input.all();

let redisResult = '';
for (const item of redisInputs) {
  if (item.json.redis_session !== undefined) {
    redisResult = item.json.redis_session;
    break;
  }
}

let sessionExists = false;
if (redisResult && redisResult !== '') {
  try {
    const session = typeof redisResult === 'string' ? JSON.parse(redisResult) : redisResult;
    const sessionDate = session.date || '';
    const today = new Date().toISOString().split('T')[0];

    if (sessionDate === today) {
      sessionExists = true;
    }
  } catch (error) {
    console.log('Redis parse error:', error.message);
  }
}

const now = new Date();

if (sessionExists) {
  return {
    skip: true,
    skip_reason: 'SESSION_EXISTS',
    slack_user_id: devData.slack_user_id,
    developer_id: devData.developer_id,
    full_name: devData.full_name,
    timestamp: now.toISOString()
  };
}

return {
  skip: false,
  slack_user_id: devData.slack_user_id,
  developer_id: devData.developer_id,
  full_name: devData.full_name,
  client_name: devData.client_name || '',
  team_role: devData.team_role || ''
};

const devData = $('Should proceed with evening session').first().json;
const airtableInputs = $input.all();

let airtableResult = null;
for (const item of airtableInputs) {
  if (item.json.id) {
    airtableResult = item.json;
    break;
  }
}

if (!airtableResult || !airtableResult.id) {
  return {
    skip: true,
    skip_reason: 'AIRTABLE_FAILED',
    error: 'Failed to create Airtable record',
    slack_user_id: devData.slack_user_id,
    developer_id: devData.developer_id,
    full_name: devData.full_name
  };
}

const now = new Date();
const today = now.toISOString().split('T')[0];

const sessionData = {
  user_id: devData.slack_user_id,
  developer_id: devData.developer_id,
  full_name: devData.full_name,
  client_name: devData.client_name || '',
  team_role: devData.team_role || '',
  current_question: 1,
  status: 'Active',
  date: today,
  started_at: now.toISOString(),
  airtable_record_id: airtableResult.id,
  answers: {
    answer_1: null,
    answer_2: null,
    answer_3: null,
    answer_4: null
  }
};

return {
  skip: false,
  redis_key: `standup:evening:${devData.slack_user_id}`,
  redis_value: JSON.stringify(sessionData),
  session_data: sessionData,
  slack_user_id: devData.slack_user_id,
  full_name: devData.full_name,
  developer_id: devData.developer_id,
  airtable_id: airtableResult.id
};

const sessionData = $('Store evening session in Redis').first().json;
const slackInputs = $input.all();

let slackResult = null;
for (const item of slackInputs) {
  if (item.json.ok !== undefined || item.json.error !== undefined) {
    slackResult = item.json;
    break;
  }
}

let slackSuccess = true;
if (slackResult !== null) {
  if (slackResult.ok === false || String(JSON.stringify(slackResult)).toLowerCase().includes('error')) {
    slackSuccess = false;
  }
}

const now = new Date();

return {
  status: slackSuccess ? 'SUCCESS' : 'SLACK_FAILED',
  slack_success: slackSuccess,
  redis_success: true,
  slack_user_id: sessionData.slack_user_id,
  developer_id: sessionData.developer_id,
  full_name: sessionData.full_name,
  airtable_id: sessionData.airtable_id,
  timestamp: now.toISOString()
};
